function clearWorksheetRowsAfterHeader(worksheet: XLSX.WorkSheet, headerRowIndex = 0) {
  const range = XLSX.utils.decode_range(worksheet["!ref"] || "A1");
  for (let row = headerRowIndex + 1; row <= range.e.r; row += 1) {
    for (let col = range.s.c; col <= range.e.c; col += 1) {
      delete worksheet[XLSX.utils.encode_cell({ r: row, c: col })];
    }
  }
}

function daysDiff(dateText: string) {
  if (!dateText) return Number.POSITIVE_INFINITY;
  const target = new Date(dateText).getTime();
  const now = new Date().getTime();
  return Math.ceil((target - now) / (1000 * 60 * 60 * 24));
}

function getAge(birthDate: string, referenceDate?: Date) {
  if (!birthDate) return null;
  const date = new Date(birthDate);
  if (Number.isNaN(date.getTime())) return null;
  const now = referenceDate ? new Date(referenceDate) : new Date();
  let age = now.getFullYear() - date.getFullYear();
  if (now.getMonth() < date.getMonth() || (now.getMonth() === date.getMonth() && now.getDate() < date.getDate())) {
    age -= 1;
  }
  return age;
}

// 병역 체계 기준 상수
const RESERVE_MAX_YEAR = 8;           // 예비군 1~8년차 (전역 후 8년)
const CIVIL_DEFENSE_END_AGE = 40;     // 민방위 종료 연령(만) — 만40세 초과 시 대상아님
const CIVIL_DEFENSE_MAX_YEARS = 5;    // 민방위 1~5년차까지만 관리(확정 정책). 6년차 이상은 대상아님(민방위 종료)
const CIVIL_DEFENSE_AGE_START = 36;   // 전역일이 없을 때 연령 기반 민방위 시작(만) → 1년차

const MILITARY_NONE = { category: "대상아님" as const, reserveYear: 0, civilYear: 0, trainingYear: 0 };
type MilitaryStatus = { category: "예비군" | "민방위" | "대상아님"; reserveYear: number; civilYear: number; trainingYear: number };

// 전역일 기준 예비군 연차(전역연도=1년차). 미전역/미입력이면 null.
function getReserveYearRaw(person: MilitaryPersonnel, referenceYear?: number): number | null {
  if (!person.dischargeDate) return null;
  const dischargeDate = new Date(person.dischargeDate);
  if (Number.isNaN(dischargeDate.getTime())) return null;
  const referenceDate = referenceYear ? new Date(referenceYear, 11, 31) : new Date();
  if (dischargeDate > referenceDate) return null; // 아직 미전역(현역)
  return referenceDate.getFullYear() - dischargeDate.getFullYear() + 1;
}

// 전역연도=1 기준 누적 연차(equivYear)로부터 예비군/민방위/대상아님 판정.
// 1~8 예비군, 9년차부터 민방위(=equivYear-8년차), 연령(또는 상한) 초과 시 대상아님.
function fromReserveEquivYear(equivYear: number, age: number | null): MilitaryStatus {
  if (equivYear >= 1 && equivYear <= RESERVE_MAX_YEAR) {
    return { category: "예비군", reserveYear: equivYear, civilYear: 0, trainingYear: equivYear };
  }
  if (equivYear > RESERVE_MAX_YEAR) {
    const civilYear = equivYear - RESERVE_MAX_YEAR; // 9년차 → 민방위 1년차
    // 확정 정책: 민방위 1~5년차만 관리(6년차 이상 대상아님), 나이 알 수 있으면 만40세 이하만
    const valid = civilYear >= 1 && civilYear <= CIVIL_DEFENSE_MAX_YEARS && (age == null || age <= CIVIL_DEFENSE_END_AGE);
    if (valid) {
      return { category: "민방위", reserveYear: 0, civilYear, trainingYear: civilYear };
    }
  }
  return MILITARY_NONE;
}

// 통합 판정 — 자동계산 / 수동(자동증가) / 수동(고정) 모두 처리. 상호배타.
function computeMilitaryStatus(person: MilitaryPersonnel, referenceYear?: number): MilitaryStatus {
  const refYear = referenceYear ?? new Date().getFullYear();
  const referenceDate = new Date(refYear, 11, 31);
  const age = getAge(person.birthDate || "", referenceDate);
  const mode = person.calculationMode;

  // 수동 모드(고정 manual / 자동증가 manualAuto)
  if ((mode === "manual" || mode === "manualAuto") && person.manualCategory) {
    const baseYear = Number(person.manualYear) || 0;
    // 자동증가: (현재 기준연도 - 수동 기준연도)만큼 연차 증가. 고정: 증가 없음.
    const increment =
      mode === "manualAuto" && person.manualBaseYear
        ? Math.max(0, refYear - (Number(person.manualBaseYear) || refYear))
        : 0;
    if (person.manualCategory === "예비군") {
      return fromReserveEquivYear(baseYear + increment, age);
    }
    if (person.manualCategory === "민방위") {
      const civilYear = Math.max(1, baseYear + increment);
      // 확정 정책: 민방위 1~5년차만 관리(고정 6년차 이상도 대상아님), 나이 알면 만40세 이하만
      const valid = civilYear <= CIVIL_DEFENSE_MAX_YEARS && (age == null || age <= CIVIL_DEFENSE_END_AGE);
      return valid
        ? { category: "민방위", reserveYear: 0, civilYear, trainingYear: civilYear }
        : MILITARY_NONE;
    }
    return MILITARY_NONE;
  }

  // 확정 정책: 전역일이 기준연도보다 미래이면 아직 전역 전(현역/전역예정) → 대상아님.
  // (나이 기반 민방위 분기로 넘어가 오분류되는 것을 방지)
  if (person.dischargeDate) {
    const dd = new Date(person.dischargeDate);
    if (!Number.isNaN(dd.getTime()) && dd > referenceDate) {
      return MILITARY_NONE;
    }
  }

  // 자동계산 — 전역일 기준(9년차부터 민방위 자동 전환)
  const reserveYearRaw = getReserveYearRaw(person, referenceYear);
  if (reserveYearRaw != null && reserveYearRaw >= 1) {
    return fromReserveEquivYear(reserveYearRaw, age);
  }

  // 전역일 없음 — 연령 기반 민방위 판정(만 36~40세)
  if (age != null && age >= CIVIL_DEFENSE_AGE_START && age <= CIVIL_DEFENSE_END_AGE) {
    const civilYear = age - (CIVIL_DEFENSE_AGE_START - 1);
    return { category: "민방위", reserveYear: 0, civilYear, trainingYear: civilYear };
  }
  // 부대/상태에 민방위 명시
  const branch = person.serviceBranch?.toLowerCase() || "";
  const status = person.status?.toLowerCase() || "";
  if (/민방위|civil/i.test(branch) || /민방위|civil/i.test(status)) {
    return { category: "민방위", reserveYear: 0, civilYear: 1, trainingYear: 1 };
  }
  return MILITARY_NONE;
}

function getMilitaryCategory(person: MilitaryPersonnel, referenceYear?: number) {
  return computeMilitaryStatus(person, referenceYear).category;
}

// 훈련유형 판정용 연차(예비군=예비군연차, 민방위=민방위연차)
function getTrainingYear(person: MilitaryPersonnel, referenceYear?: number) {
  return computeMilitaryStatus(person, referenceYear).trainingYear;
}

// 예비군 연차 (현재구분=예비군이 아니면 0 → 상호배타)
function getReserveAnnualLeave(person: MilitaryPersonnel, referenceYear?: number) {
  return computeMilitaryStatus(person, referenceYear).reserveYear;
}

// 민방위 연차 (현재구분=민방위가 아니면 0 → 상호배타)
function getCivilDefenseAnnualLeave(person: MilitaryPersonnel, referenceYear?: number) {
  return computeMilitaryStatus(person, referenceYear).civilYear;
}

function getRequiredTraining(person: MilitaryPersonnel, referenceYear?: number) {
  const category = getMilitaryCategory(person, referenceYear);
  if (category === "예비군") {
    const serviceYear = getTrainingYear(person, referenceYear);
    if (!serviceYear) {
      return { label: "자동판정불가", hours: 0 };
    }
    if (serviceYear >= 1 && serviceYear <= 4) {
      return { label: "동원훈련 또는 동미참훈련", hours: 28 };
    }
    if (serviceYear >= 5 && serviceYear <= 6) {
      return { label: "기본훈련 + 작계훈련", hours: 14 };
    }
    if (serviceYear >= 7 && serviceYear <= 8) {
      return { label: "훈련 비대상(7~8년차)", hours: 0 };
    }
    return { label: "예비군 대상아님", hours: 0 };
  }
  if (category === "민방위") {
    return { label: "민방위교육", hours: 4 };
  }
  return { label: "교육대상아님", hours: 0 };
}

function calculateDormContractStatus(contract: DormContractFormLike, dorms: Dorm[], occupants: Occupant[]): DormContractStatus {
  const today = new Date().toISOString().slice(0, 10);
  const contractStart = contract.contractStart || "";
  const contractEnd = contract.contractEnd || "";

  const dorm = dorms.find(
    (d) =>
      d.address === contract.address &&
      d.buildingName === contract.buildingName &&
      d.dong === contract.dong &&
      d.roomHo === contract.roomHo
  );

  const occupantCount = dorm
    ? occupants.filter(
        (o) =>
          o.dormId === dorm.id && ["거주중", "만료예정"].includes(o.status)
      ).length
    : 0;

  if (contract.contractStatus === "해지") return "해지";
  if (contract.contractStatus === "종료") return "종료";
  if (contractEnd && contractEnd < today) return "연장";
  if (contractEnd && daysDiff(contractEnd) <= 30) return "만료예정";
  if (contractStart && contractStart <= today) return occupantCount > 0 ? "진행중" : "공실";
  return "공실";
}


function calculateNewHireResidenceStatus(employee: NewHireFormLike): NewHireResidenceStatus {
  const today = new Date().toISOString().slice(0, 10);
  const moveInDate = employee.moveInDate || "";
  const moveOutDate = employee.moveOutDate || "";
  const expectedMoveOutDate = employee.expectedMoveOutDate || "";
  const actualMoveOutDate = employee.actualMoveOutDate || "";
  const hasAddressInfo = Boolean(employee.buildingName?.trim() && employee.dong?.trim() && employee.roomHo?.trim());

  const endDate = moveOutDate || expectedMoveOutDate;

  if (!hasAddressInfo || !moveInDate) return "대기중";
  if (actualMoveOutDate && actualMoveOutDate <= today) return "퇴실";
  if (endDate && endDate < today && !actualMoveOutDate) return "연장";
  if (endDate && daysDiff(endDate) <= 30) return "만료예정";
  if (moveInDate && moveInDate <= today) return "거주중";
  return "대기중";
}

function calculateMoveInType(
  employee: NewHireFormLike,
  allEmployees: NewHireEmployee[]
): MoveInType {
  const hasAddressInfo = Boolean(employee.buildingName?.trim() && employee.dong?.trim() && employee.roomHo?.trim());
  if (!hasAddressInfo) return "대기자";

  const previousRecords = allEmployees
    .filter((e) => e.id !== employee.id && e.name === employee.name && e.phone === employee.phone)
    .sort((a, b) => a.createdAt.localeCompare(b.createdAt));

  if (previousRecords.length === 0) return "신규";

  const last = previousRecords[previousRecords.length - 1];
  const currentMoveInDate = employee.moveInDate || "";
  const lastEndDate = last.moveOutDate || last.expectedMoveOutDate || "";

  if (!currentMoveInDate) return "재입주";
  if (
    lastEndDate &&
    currentMoveInDate === addDays(lastEndDate, 1) &&
    employee.buildingName === last.buildingName &&
    employee.dong === last.dong &&
    employee.roomHo === last.roomHo
  ) {
    return "연장";
  }

  return "재입주";
}

// 신입사원 상태/유형/미배정 단일 기준(대시보드·메뉴·필터·Excel 공통).
// 저장값 우선, "자동선택"일 때만 계산값 사용. 미배정 = 삭제 아님 + 퇴실 아님 + dormId 없음.
function getNewHireStatus(h: NewHireEmployee): NewHireResidenceStatus {
  return (h.residenceStatus as string) === "자동선택" ? calculateNewHireResidenceStatus(h) : h.residenceStatus;
}
function getNewHireType(h: NewHireEmployee, allEmployees: NewHireEmployee[]): MoveInType {
  return (h.moveInType as string) === "자동선택" ? calculateMoveInType(h, allEmployees) : h.moveInType;
}
function isUnassignedNewHire(h: NewHireEmployee): boolean {
  if (h.isDeleted) return false;
  if (getNewHireStatus(h) === "퇴실") return false; // 퇴실자는 미배정 통계에서 제외
  return !(h.dormId && h.dormId.trim());
}

function addDays(dateText: string, days: number) {
  if (!dateText) return "";
  const date = new Date(dateText);
  if (Number.isNaN(date.valueOf())) return "";
  date.setDate(date.getDate() + days);
  return date.toISOString().slice(0, 10);
}

function calculateDormContractType(
  contract: DormContractFormLike,
  dormContracts: DormContract[],
  editingId: string | null
): ContractType {
  const sameContracts = dormContracts
    .filter(
      (c) =>
        c.id !== editingId &&
        c.address === contract.address &&
        c.buildingName === contract.buildingName &&
        c.dong === contract.dong &&
        c.roomHo === contract.roomHo
    )
    .sort((a, b) => a.createdAt.localeCompare(b.createdAt));

  if (sameContracts.length === 0) return "신규";
  const last = sameContracts[sameContracts.length - 1];
  if (!contract.contractStart) return "신규";
  const lastEnd = last.contractEnd || "";

  if (last.contractStatus === "해지" && contract.contractStart > lastEnd) return "해지후신규";

  const sameTerms =
    last.landlordName === contract.landlordName &&
    last.landlordPhone === contract.landlordPhone &&
    last.realEstateName === contract.realEstateName &&
    last.realEstatePhone === contract.realEstatePhone &&
    last.contractAmount === contract.contractAmount &&
    last.prepaymentDeposit === contract.prepaymentDeposit &&
    last.deposit === contract.deposit &&
    last.monthlyRentOrMaintenance === contract.monthlyRentOrMaintenance;

  const contiguous = contract.contractStart === addDays(lastEnd, 1);
  if (contiguous && sameTerms) return "연장";
  if (!sameTerms) return "재계약";
  return "재계약";
}

function daysBetween(start: string, end: string) {
  if (!start || !end) return 0;
  const startDate = new Date(start);
  const endDate = new Date(end);
  return Math.ceil((endDate.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24));
}

function badgeColor(theme: ThemeSettings, value: string) {
  return theme.colorMap[value] || "#E5E7EB";
}

// 성별 정규화 + 색상(정산관리 등): 남=파랑, 여=분홍, 혼합=보라, 미지정=회색
function normalizeGenderLabel(g?: string): "남" | "여" | "혼합" | "미지정" {
  const s = String(g || "").trim().toLowerCase();
  if (s === "남" || s === "남성" || s === "m" || s === "male") return "남";
  if (s === "여" || s === "여성" || s === "f" || s === "female") return "여";
  if (s === "혼합" || s === "혼성" || s === "공용" || s === "mixed") return "혼합";
  return "미지정";
}
function genderColor(g?: string): string {
  switch (normalizeGenderLabel(g)) {
    case "남": return "#3b82f6";
    case "여": return "#ec4899";
    case "혼합": return "#8b5cf6";
    default: return "#9ca3af";
  }
}

