  // const canDeleteTab = (tabKey: string, user: LoginUser | null): boolean => {
  //   if (!user) return false;
  //   const permission = systemSettings.permissions.find(p => p.role === user.role && p.tabKey === tabKey);
  //   return permission?.canDelete ?? false;
