                  <div className="text-xs text-slate-500">자동계산: {calculateDormContractType(dormContractForm, dormContracts, editingDormContractId)}{dormContractForm.contractType !== "자동선택" ? " (참고값 · 저장은 수동 선택값 우선)" : ""}</div>
